import { Link, useNavigate, useLocation } from "react-router-dom";
import { useState } from "react";

export default function Navbar() {

  const navigate = useNavigate();
  const location = useLocation();
  const pathname = location.pathname || "/";

  const accessToken = localStorage.getItem("accessToken");
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  const isAuthPage =
    pathname === "/login" || pathname === "/register";

  const isLoggedIn = Boolean(accessToken) && !isAuthPage;
  const isAdmin = user?.role === "admin";

  const [open, setOpen] = useState(false);

  const logout = () => {

    localStorage.removeItem("accessToken");
    localStorage.removeItem("refreshToken");
    localStorage.removeItem("user");

    setOpen(false);

    navigate("/login", { replace: true });

  };

  return (

    <nav className="bg-white/90 backdrop-blur-md shadow-md sticky top-0 z-50">

      <div className="max-w-7xl mx-auto px-5 py-3 flex justify-between items-center">

        {/* LOGO */}

        <Link
          to={isLoggedIn ? "/dashboard" : "/login"}
          className="text-2xl font-extrabold tracking-wide transition hover:scale-105"
        >
          <span className="text-blue-600">we</span>
          <span className="text-gray-900">FOUND</span>
          <span className="text-green-600">it</span>
        </Link>


        {/* DESKTOP MENU */}

        <div className="hidden md:flex items-center gap-6">

          <NavLink to="/about" pathname={pathname}>
            About
          </NavLink>

          <NavLink to="/returned" pathname={pathname}>
            Returned
          </NavLink>

          {isLoggedIn && (
            <>
              <NavLink to="/dashboard" pathname={pathname}>
                Dashboard
              </NavLink>

              <NavLink to="/my-posts" pathname={pathname}>
                My Posts
              </NavLink>
            </>
          )}

          {isAdmin && (
            <NavLink to="/admin" pathname={pathname}>
              Admin
            </NavLink>
          )}

          {!isLoggedIn && (
            <>
              <NavLink to="/login" pathname={pathname}>
                Login
              </NavLink>

              <NavLink to="/register" pathname={pathname}>
                Register
              </NavLink>
            </>
          )}

          {isLoggedIn && (

            <div className="flex items-center gap-3 ml-4">

              <span className="text-sm font-semibold text-gray-700">
                {user?.name || "User"}
              </span>

              {isAdmin && (
                <span className="bg-purple-100 text-purple-700 text-xs px-2 py-0.5 rounded-full font-bold">
                  ADMIN
                </span>
              )}

              <button
                onClick={logout}
                className="ml-3 px-4 py-1.5 rounded-lg bg-red-500 text-white hover:bg-red-600 transition shadow-sm"
              >
                Logout
              </button>

            </div>

          )}

        </div>


        {/* MOBILE BUTTON */}

        <button
          onClick={() => setOpen(!open)}
          className="md:hidden flex flex-col gap-1"
        >
          <span className={`hamburger ${open ? "open" : ""}`} />
          <span className={`hamburger ${open ? "open" : ""}`} />
          <span className={`hamburger ${open ? "open" : ""}`} />
        </button>

      </div>


      {/* MOBILE MENU */}

      <div
        className={`md:hidden transition-all duration-300 overflow-hidden
        ${open ? "max-h-96 opacity-100" : "max-h-0 opacity-0"}`}
      >

        <div className="bg-white border-t flex flex-col py-3">

          <MobileLink to="/about" setOpen={setOpen}>
            About
          </MobileLink>

          <MobileLink to="/returned" setOpen={setOpen}>
            Returned
          </MobileLink>

          {isLoggedIn && (
            <>
              <MobileLink to="/dashboard" setOpen={setOpen}>
                Dashboard
              </MobileLink>

              <MobileLink to="/my-posts" setOpen={setOpen}>
                My Posts
              </MobileLink>
            </>
          )}

          {isAdmin && (
            <MobileLink to="/admin" setOpen={setOpen}>
              Admin
            </MobileLink>
          )}

          {!isLoggedIn && (
            <>
              <MobileLink to="/login" setOpen={setOpen}>
                Login
              </MobileLink>

              <MobileLink to="/register" setOpen={setOpen}>
                Register
              </MobileLink>
            </>
          )}

          {isLoggedIn && (
            <button
              onClick={logout}
              className="text-left px-5 py-2 text-red-600 hover:bg-red-50"
            >
              Logout
            </button>
          )}

        </div>

      </div>

    </nav>

  );

}


/* NAV LINK */

function NavLink({ to, children, pathname }) {

  const active = pathname === to;

  return (

    <Link
      to={to}
      className={`relative font-medium transition
      ${active ? "text-blue-600" : "text-gray-700 hover:text-blue-600"}`}
    >

      {children}

      <span
        className={`absolute left-0 -bottom-1 h-0.5 bg-blue-600 transition-all duration-300
        ${active ? "w-full" : "w-0 group-hover:w-full"}`}
      />

    </Link>

  );

}


/* MOBILE LINK */

function MobileLink({ to, children, setOpen }) {

  return (

    <Link
      to={to}
      onClick={() => setOpen(false)}
      className="px-5 py-2 text-gray-700 hover:bg-gray-100"
    >

      {children}

    </Link>

  );

}
